import{_ as t,o as e,c as o,O as a}from"./chunks/framework.bdcb0ee1.js";const m=JSON.parse('{"title":"AutoMod","description":"","frontmatter":{},"headers":[],"relativePath":"administration/config/automod.md","filePath":"administration/config/automod.md","lastUpdated":1773166402000}'),i={name:"administration/config/automod.md"},l=a('<h1 id="automod" tabindex="-1">AutoMod <a class="header-anchor" href="#automod" aria-label="Permalink to &quot;AutoMod&quot;">​</a></h1><p>AutoMod allows you to create automated moderation rules that trigger when new topics are created. Rules can automatically close, pin, move topics, add a title prefix, or post an automatic reply.</p><p>You can manage AutoMod rules from the <strong>AutoMod</strong> section in the Admin Control Panel.</p><nav class="table-of-contents"><ul><li><a href="#creating-a-rule">Creating a Rule</a></li><li><a href="#available-actions">Available Actions</a></li><li><a href="#forum-targeting">Forum Targeting</a></li><li><a href="#applying-automod-manually">Applying AutoMod Manually</a></li><li><a href="#notes">Notes</a></li></ul></nav><h2 id="creating-a-rule" tabindex="-1">Creating a Rule <a class="header-anchor" href="#creating-a-rule" aria-label="Permalink to &quot;Creating a Rule&quot;">​</a></h2><p>To create a new AutoMod rule, go to <strong>AutoMod &gt; Topic AutoMod</strong> and click <strong>Create AutoMod Rule</strong>.</p><p>Fill in the following fields:</p><ul><li><strong>Name</strong>: A label to identify the rule in the admin area.</li><li><strong>Topic Prefix</strong>: An optional text prefix that will be prepended to the topic title (max 255 characters). For example, <code>[Approved]</code> or <code>[Info]</code>.</li><li><strong>Target Forum</strong>: Optionally select a forum to move matching topics into.</li><li><strong>Auto-Reply</strong>: An optional message that will be posted as an automatic reply to the topic (max 65,000 characters). BBCode is supported.</li><li><strong>Close Topic</strong>: If enabled, the topic will be automatically closed (locked) so no further replies can be posted.</li><li><strong>Pin Topic</strong>: If enabled, the topic will be automatically pinned to the top of the forum.</li><li><strong>Global</strong>: If enabled, the rule applies to all forums. If disabled, you can select specific forums where the rule should apply.</li></ul><img width="1955" height="1071" alt="image" src="https://github.com/user-attachments/assets/8f09aca9-bada-46e3-9598-d5012894501b"><h2 id="available-actions" tabindex="-1">Available Actions <a class="header-anchor" href="#available-actions" aria-label="Permalink to &quot;Available Actions&quot;">​</a></h2><p>Each rule can perform one or more of the following actions when triggered:</p><table><thead><tr><th>Action</th><th>Description</th></tr></thead><tbody><tr><td>Close topic</td><td>Locks the topic to prevent further replies.</td></tr><tr><td>Pin topic</td><td>Pins the topic to the top of the forum listing.</td></tr><tr><td>Move to forum</td><td>Moves the topic to a different forum section.</td></tr><tr><td>Add prefix</td><td>Prepends text to the topic title.</td></tr><tr><td>Post auto-reply</td><td>Automatically creates a reply in the topic with the configured message.</td></tr></tbody></table><p>Actions are applied in the order listed above. You can combine multiple actions in a single rule.</p><h2 id="forum-targeting" tabindex="-1">Forum Targeting <a class="header-anchor" href="#forum-targeting" aria-label="Permalink to &quot;Forum Targeting&quot;">​</a></h2><ul><li><strong>Global rules</strong> apply to topics created in any forum on your board.</li><li><strong>Targeted rules</strong> apply only to topics created in the selected forums.</li></ul><p>When editing a rule, you can change the forum selection at any time. Updating the forums list will only affect new topics — existing topics that have already been processed will not be modified.</p><h2 id="applying-automod-manually" tabindex="-1">Applying AutoMod Manually <a class="header-anchor" href="#applying-automod-manually" aria-label="Permalink to &quot;Applying AutoMod Manually&quot;">​</a></h2><p>In addition to automatic triggering, moderators can also apply AutoMod rules manually:</p><ul><li><strong>Single topic</strong>: From a topic page, moderators can trigger AutoMod rules on that specific topic.</li><li><strong>Bulk</strong>: From a forum listing, moderators can apply AutoMod rules to multiple selected topics at once.</li></ul><h2 id="notes" tabindex="-1">Notes <a class="header-anchor" href="#notes" aria-label="Permalink to &quot;Notes&quot;">​</a></h2><ul><li>AutoMod rules are only triggered when a new topic is created. Editing a topic does not re-trigger rules.</li><li>Rules are processed in the order they were created. If multiple rules match, all of them will be applied.</li><li>Auto-replies are posted as system messages and are not attributed to any specific user.</li><li>AutoMod is particularly useful for support forums (auto-reply with guidelines), announcement sections (auto-pin and close), or intake forums (move to appropriate section after posting).</li></ul>',21),r=[l];function n(s,d,c,u,p,h){return e(),o("div",null,r)}const f=t(i,[["render",n]]);export{m as __pageData,f as default};
